const STORAGE_KEY = 'notepad-content';
const ON_AUTO_SAVED = 'OnAutoSaved';

let dotNetRef = null;
let autoSaveInterval = null;
let dirty = false;

function beforeUnloadHandler(e) {
    if (dirty) {
        e.preventDefault();
    }
}

export function initialize(ref) {
    dotNetRef = ref;

